import java.io.*;
import org.apache.commons.text.StringEscapeUtils;

public class SecureXSSExample {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String userName = br.readLine();

        // Sanitize user input to prevent XSS attacks
        String safeUserName = StringEscapeUtils.escapeHtml4(userName);

        // Output sanitized user input to the webpage
        System.out.println("<h1>Welcome, " + safeUserName + "!</h1>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
